files.content:
.mrg-collapsible {
  border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
  min-inline-size: 0;
}

.mrg-collapsible__trigger {
  align-items: center;
  background: var(--mrg-semantic-color-background-surface-sunken);
  border: 0;
  box-sizing: border-box;
  color: inherit;
  cursor: pointer;
  display: flex;
  font: inherit;
  font-weight: var(--mrg-semantic-font-weight-strong);
  gap: var(--mrg-semantic-space-inline-md);
  inline-size: 100%;
  justify-content: space-between;
  min-block-size: var(--mrg-semantic-density-control-height);
  padding: var(--mrg-semantic-space-stack-md) var(--mrg-semantic-space-inline-lg);
  text-align: start;
}

.mrg-collapsible__trigger[data-focus-visible] {
  outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
  outline-offset: calc(var(--mrg-semantic-focus-width) * -1);
}

.mrg-collapsible__trigger[data-disabled] {
  cursor: not-allowed;
  opacity: var(--mrg-semantic-opacity-disabled);
}

[data-slot="collapsible-trigger-indicator"] {
  flex: none;
  transition: transform var(--mrg-semantic-motion-duration-feedback)
    var(--mrg-semantic-motion-easing-standard);
}

.mrg-collapsible[data-expanded] [data-slot="collapsible-trigger-indicator"] {
  transform: rotate(180deg);
}

.mrg-collapsible__content {
  min-inline-size: 0;
  padding: var(--mrg-semantic-space-stack-lg) var(--mrg-semantic-space-inline-lg);
}

@media (prefers-reduced-motion: reduce) {
  [data-slot="collapsible-trigger-indicator"] {
    transition: none;
  }
}

@media (forced-colors: active) {
  .mrg-collapsible__trigger[data-focus-visible] {
    outline-color: Highlight;
  }
}

"use client";

import { forwardRef, type ReactNode } from "react";
import {
  Button as AriaButton,
  Disclosure as AriaDisclosure,
  DisclosurePanel as AriaDisclosurePanel,
  type ButtonProps as AriaButtonProps,
  type DisclosurePanelProps as AriaDisclosurePanelProps,
  type DisclosureProps as AriaDisclosureProps,
} from "react-aria-components/Disclosure";

import "./collapsible.css";

export interface CollapsibleRootProps extends Omit<
  AriaDisclosureProps,
  "children" | "className" | "defaultExpanded" | "isDisabled" | "isExpanded" | "onExpandedChange"
> {
  readonly children: ReactNode;
  readonly defaultOpen?: boolean;
  readonly disabled?: boolean;
  readonly onOpenChange?: (open: boolean) => void;
  readonly open?: boolean;
}

export const CollapsibleRoot = forwardRef<HTMLDivElement, CollapsibleRootProps>(
  function CollapsibleRoot(
    { children, defaultOpen = false, disabled = false, onOpenChange, open, ...props },
    ref,
  ) {
    return (
      <AriaDisclosure
        {...props}
        {...(onOpenChange === undefined ? {} : { onExpandedChange: onOpenChange })}
        {...(open === undefined ? {} : { isExpanded: open })}
        className="mrg-collapsible"
        data-slot="collapsible"
        defaultExpanded={defaultOpen}
        isDisabled={disabled}
        ref={ref}
      >
        {children}
      </AriaDisclosure>
    );
  },
);

CollapsibleRoot.displayName = "CollapsibleRoot";

export interface CollapsibleTriggerProps extends Omit<AriaButtonProps, "children" | "className"> {
  readonly children: ReactNode;
}

export const CollapsibleTrigger = forwardRef<HTMLButtonElement, CollapsibleTriggerProps>(
  function CollapsibleTrigger({ children, ...props }, ref) {
    return (
      <AriaButton
        {...props}
        className="mrg-collapsible__trigger"
        data-slot="collapsible-trigger"
        ref={ref}
        slot="trigger"
      >
        <span data-slot="collapsible-trigger-label">{children}</span>
        <span aria-hidden="true" data-slot="collapsible-trigger-indicator">
          ▾
        </span>
      </AriaButton>
    );
  },
);

CollapsibleTrigger.displayName = "CollapsibleTrigger";

export interface CollapsibleContentProps extends Omit<
  AriaDisclosurePanelProps,
  "children" | "className"
> {
  readonly children: ReactNode;
}

export const CollapsibleContent = forwardRef<HTMLDivElement, CollapsibleContentProps>(
  function CollapsibleContent({ children, ...props }, ref) {
    return (
      <AriaDisclosurePanel
        {...props}
        className="mrg-collapsible__content"
        data-slot="collapsible-content"
        ref={ref}
      >
        {children}
      </AriaDisclosurePanel>
    );
  },
);

CollapsibleContent.displayName = "CollapsibleContent";

export const Collapsible = {
  Content: CollapsibleContent,
  Root: CollapsibleRoot,
  Trigger: CollapsibleTrigger,
} as const;

export {
  Collapsible,
  CollapsibleContent,
  CollapsibleRoot,
  CollapsibleTrigger,
  type CollapsibleContentProps,
  type CollapsibleRootProps,
  type CollapsibleTriggerProps,
} from "./collapsible";
